        PB.encode(e, 11, x.variant[]::Expression)
    elseif x.variant.name === :sqrt
        PB.encode(e, 12, x.variant[]::Expression)
    elseif x.variant.name === :pow
        PB.encode(e, 13, x.variant[]::PowExpression)
    elseif x.variant.name === :exp
        PB.encode(e, 14, x.variant[]::Expression)
    elseif x.variant.name === :log10
        PB.encode(e, 15, x.variant[]::Expression)
    elseif x.variant.name === :ln
        PB.encode(e, 16, x.variant[]::Expression)
    elseif x.variant.name === :exp_decay
        PB.encode(e, 17, x.variant[]::DecayParamsExpression)
    elseif x.variant.name === :gauss_decay
        PB.encode(e, 18, x.variant[]::DecayParamsExpression)
    elseif x.variant.name === :lin_decay
        PB.encode(e, 19, x.variant[]::DecayParamsExpression)
    end
    return position(e.io) - initpos
end
function PB._encoded_size(x::Expression)
    encoded_size = 0
    if isnothing(x.variant);
    elseif x.variant.name === :constant
        encoded_size += PB._encoded_size(x.variant[]::Float32, 1)
    elseif x.variant.name === :variable
