    elseif x.variant.name === :abs
        encoded_size += PB._encoded_size(x.variant[]::Expression, 11)
    elseif x.variant.name === :sqrt
        encoded_size += PB._encoded_size(x.variant[]::Expression, 12)
    elseif x.variant.name === :pow
        encoded_size += PB._encoded_size(x.variant[]::PowExpression, 13)
    elseif x.variant.name === :exp
